import { metadata, wait, task } from "@trigger.dev/sdk";

const trial_id = "realtime_progress_metadata__jrQdrmN";

export const progressTask = task({
  id: `progressTask-${trial_id}`,
  run: async () => {
    const totalItems = 10;

    for (let i = 0; i < totalItems; i++) {
      // Calculate progress percentage
      const percentage = Math.round(((i + 1) / totalItems) * 100);

      // Update metadata with current progress
      await metadata.set("progress", percentage);

      // Append log entry for this item
      const message = `Processing item ${i + 1} of ${totalItems} (${percentage}%)`;
      await metadata.append("logs", message);

      // Simulate work
      await wait.for({ seconds: 1 });
    }

    // Mark as complete
    await metadata.set("progress", 100);
    await metadata.append("logs", "All items processed successfully");

    return {
      status: "completed",
      itemsProcessed: totalItems,
    };
  },
});

